use crate::types::{DecideInput, DecideOutput};

const PI: f64 = 3.1415926535;

pub fn realcompare(a: f64, b: f64) -> &'static str {
    if a == b {
        return "EQ";
    }

    let abs_max = a.abs().max(b.abs());
    if abs_max == 0.0 {
        return "EQ";
    }

    let exponent = abs_max.log10().floor() as i32;
    let tolerance = 0.5 * 10f64.powi(exponent - 5);
    let diff = (a - b).abs();

    if diff <= tolerance {
        "EQ"
    } else if a < b {
        "LT"
    } else {
        "GT"
    }
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let mut cmv = vec![false; 15];
    cmv[0] = lic1(input);
    cmv[1] = lic2(input);
    cmv[2] = lic3(input);
    cmv[3] = lic4(input);
    cmv[4] = lic5(input);
    cmv[5] = lic6(input);
    cmv[6] = lic7(input);
    cmv[7] = lic8(input);
    cmv[8] = lic9(input);
    cmv[9] = lic10(input);
    cmv[10] = lic11(input);
    cmv[11] = lic12(input);
    cmv[12] = lic13(input);
    cmv[13] = lic14(input);
    cmv[14] = lic15(input);

    let mut pum = vec![vec![false; 15]; 15];
    for i in 0..15 {
        pum[i][i] = input.pum_diag[i];
        for j in 0..15 {
            if i == j {
                continue;
            }

            pum[i][j] = match input.lcm[i][j].as_str() {
                "NOTUSED" => true,
                "ANDD" => cmv[i] && cmv[j],
                "ORR" => cmv[i] || cmv[j],
                _ => unreachable!("invalid LCM connector"),
            };
        }
    }

    let mut fuv = vec![false; 15];
    for i in 0..15 {
        fuv[i] = !pum[i][i] || pum[i].iter().all(|&v| v);
    }

    let launch = fuv.iter().all(|&v| v);

    DecideOutput {
        cmv,
        pum,
        fuv,
        launch,
    }
}

fn lic1(input: &DecideInput) -> bool {
    let len2 = input.parameters.length1 * input.parameters.length1;
    for i in 0..input.numpoints - 1 {
        if realcompare(dist2(input, i, i + 1), len2) == "GT" {
            return true;
        }
    }
    false
}

fn lic2(input: &DecideInput) -> bool {
    let r2 = input.parameters.radius1 * input.parameters.radius1;
    for i in 0..input.numpoints - 2 {
        if !triangle_fits_in_circle(input, i, i + 1, i + 2, r2) {
            return true;
        }
    }
    false
}

fn lic3(input: &DecideInput) -> bool {
    let threshold_low = PI - input.parameters.epsilon;
    let threshold_high = PI + input.parameters.epsilon;

    for i in 0..input.numpoints - 2 {
        let ax = input.x[i] - input.x[i + 1];
        let ay = input.y[i] - input.y[i + 1];
        let bx = input.x[i + 2] - input.x[i + 1];
        let by = input.y[i + 2] - input.y[i + 1];

        if (realcompare(ax, 0.0) == "EQ" && realcompare(ay, 0.0) == "EQ")
            || (realcompare(bx, 0.0) == "EQ" && realcompare(by, 0.0) == "EQ")
        {
            continue;
        }

        let dot = ax * bx + ay * by;
        let cross = (ax * by - ay * bx).abs();
        let angle = cross.atan2(dot);

        if realcompare(angle, threshold_low) == "LT" || realcompare(angle, threshold_high) == "GT" {
            return true;
        }
    }
    false
}

fn lic4(input: &DecideInput) -> bool {
    let threshold = 2.0 * input.parameters.area1;
    for i in 0..input.numpoints - 2 {
        let cross = triangle_cross(input, i, i + 1, i + 2).abs();
        if realcompare(cross, threshold) == "GT" {
            return true;
        }
    }
    false
}

fn lic5(input: &DecideInput) -> bool {
    let q_pts = input.parameters.q_pts;
    for start in 0..=input.numpoints - q_pts {
        let mut seen = [false; 4];
        let mut unique = 0usize;
        for idx in start..start + q_pts {
            let q = quadrant(input.x[idx], input.y[idx]) - 1;
            if !seen[q] {
                seen[q] = true;
                unique += 1;
            }
        }
        if unique > input.parameters.quads {
            return true;
        }
    }
    false
}

fn lic6(input: &DecideInput) -> bool {
    for i in 0..input.numpoints - 1 {
        if realcompare(input.x[i + 1], input.x[i]) == "LT" {
            return true;
        }
    }
    false
}

fn lic7(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }

    let n_pts = input.parameters.n_pts;
    let dist2_threshold = input.parameters.dist * input.parameters.dist;

    for start in 0..=input.numpoints - n_pts {
        let first = start;
        let last = start + n_pts - 1;

        if realcompare(dist2(input, first, last), 0.0) == "EQ" {
            for idx in start + 1..last {
                if realcompare(dist2(input, first, idx), dist2_threshold) == "GT" {
                    return true;
                }
            }
        } else {
            let line_len2 = dist2(input, first, last);
            for idx in start + 1..last {
                let cross = point_line_cross(input, first, last, idx).abs();
                if realcompare(cross * cross, dist2_threshold * line_len2) == "GT" {
                    return true;
                }
            }
        }
    }

    false
}

fn lic8(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }

    let k = input.parameters.k_pts;
    let len2 = input.parameters.length1 * input.parameters.length1;
    for i in 0..=input.numpoints - k - 2 {
        if realcompare(dist2(input, i, i + k + 1), len2) == "GT" {
            return true;
        }
    }
    false
}

fn lic9(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }

    let a = input.parameters.a_pts;
    let b = input.parameters.b_pts;
    let r2 = input.parameters.radius1 * input.parameters.radius1;
    for i in 0..=input.numpoints - a - b - 3 {
        if !triangle_fits_in_circle(input, i, i + a + 1, i + a + b + 2, r2) {
            return true;
        }
    }
    false
}

fn lic10(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }

    let c = input.parameters.c_pts;
    let d = input.parameters.d_pts;
    let low = PI - input.parameters.epsilon;
    let high = PI + input.parameters.epsilon;

    for i in 0..=input.numpoints - c - d - 3 {
        let a = i;
        let v = i + c + 1;
        let b = i + c + d + 2;
        let ux = input.x[a] - input.x[v];
        let uy = input.y[a] - input.y[v];
        let wx = input.x[b] - input.x[v];
        let wy = input.y[b] - input.y[v];

        if (realcompare(ux, 0.0) == "EQ" && realcompare(uy, 0.0) == "EQ")
            || (realcompare(wx, 0.0) == "EQ" && realcompare(wy, 0.0) == "EQ")
        {
            continue;
        }

        let dot = ux * wx + uy * wy;
        let cross = (ux * wy - uy * wx).abs();
        let angle = cross.atan2(dot);

        if realcompare(angle, low) == "LT" || realcompare(angle, high) == "GT" {
            return true;
        }
    }

    false
}

fn lic11(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }

    let e = input.parameters.e_pts;
    let f = input.parameters.f_pts;
    let threshold = 2.0 * input.parameters.area1;

    for i in 0..=input.numpoints - e - f - 3 {
        let area_cross = triangle_cross(input, i, i + e + 1, i + e + f + 2).abs();
        if realcompare(area_cross, threshold) == "GT" {
            return true;
        }
    }
    false
}

fn lic12(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }

    let g = input.parameters.g_pts;
    for i in 0..=input.numpoints - g - 2 {
        if realcompare(input.x[i + g + 1], input.x[i]) == "LT" {
            return true;
        }
    }
    false
}

fn lic13(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }

    let k = input.parameters.k_pts;
    let len1_sq = input.parameters.length1 * input.parameters.length1;
    let len2_sq = input.parameters.length2 * input.parameters.length2;
    let mut greater = false;
    let mut less = false;

    for i in 0..=input.numpoints - k - 2 {
        let d2 = dist2(input, i, i + k + 1);
        if !greater && realcompare(d2, len1_sq) == "GT" {
            greater = true;
        }
        if !less && realcompare(d2, len2_sq) == "LT" {
            less = true;
        }
        if greater && less {
            return true;
        }
    }

    false
}

fn lic14(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }

    let a = input.parameters.a_pts;
    let b = input.parameters.b_pts;
    let r1_sq = input.parameters.radius1 * input.parameters.radius1;
    let r2_sq = input.parameters.radius2 * input.parameters.radius2;
    let mut outside_r1 = false;
    let mut inside_r2 = false;

    for i in 0..=input.numpoints - a - b - 3 {
        let fits_r1 = triangle_fits_in_circle(input, i, i + a + 1, i + a + b + 2, r1_sq);
        let fits_r2 = triangle_fits_in_circle(input, i, i + a + 1, i + a + b + 2, r2_sq);

        if !fits_r1 {
            outside_r1 = true;
        }
        if fits_r2 {
            inside_r2 = true;
        }
        if outside_r1 && inside_r2 {
            return true;
        }
    }

    false
}

fn lic15(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }

    let e = input.parameters.e_pts;
    let f = input.parameters.f_pts;
    let threshold_gt = 2.0 * input.parameters.area1;
    let threshold_lt = 2.0 * input.parameters.area2;
    let mut greater = false;
    let mut less = false;

    for i in 0..=input.numpoints - e - f - 3 {
        let cross = triangle_cross(input, i, i + e + 1, i + e + f + 2).abs();
        if !greater && realcompare(cross, threshold_gt) == "GT" {
            greater = true;
        }
        if !less && realcompare(cross, threshold_lt) == "LT" {
            less = true;
        }
        if greater && less {
            return true;
        }
    }

    false
}

fn triangle_cross(input: &DecideInput, i: usize, j: usize, k: usize) -> f64 {
    let ax = input.x[j] - input.x[i];
    let ay = input.y[j] - input.y[i];
    let bx = input.x[k] - input.x[i];
    let by = input.y[k] - input.y[i];
    ax * by - ay * bx
}

fn point_line_cross(input: &DecideInput, i: usize, j: usize, k: usize) -> f64 {
    let ax = input.x[j] - input.x[i];
    let ay = input.y[j] - input.y[i];
    let bx = input.x[k] - input.x[i];
    let by = input.y[k] - input.y[i];
    ax * by - ay * bx
}

fn dist2(input: &DecideInput, i: usize, j: usize) -> f64 {
    let dx = input.x[j] - input.x[i];
    let dy = input.y[j] - input.y[i];
    dx * dx + dy * dy
}

fn quadrant(x: f64, y: f64) -> usize {
    if realcompare(x, 0.0) != "LT" && realcompare(y, 0.0) != "LT" {
        1
    } else if realcompare(x, 0.0) == "LT" && realcompare(y, 0.0) != "LT" {
        2
    } else if realcompare(x, 0.0) != "GT" && realcompare(y, 0.0) == "LT" {
        3
    } else {
        4
    }
}

fn sort_three(a: f64, b: f64, c: f64) -> (f64, f64, f64) {
    let mut x = a;
    let mut y = b;
    let mut z = c;

    if realcompare(x, y) == "GT" {
        std::mem::swap(&mut x, &mut y);
    }
    if realcompare(y, z) == "GT" {
        std::mem::swap(&mut y, &mut z);
    }
    if realcompare(x, y) == "GT" {
        std::mem::swap(&mut x, &mut y);
    }

    (x, y, z)
}

fn triangle_fits_in_circle(
    input: &DecideInput,
    i: usize,
    j: usize,
    k: usize,
    radius_sq: f64,
) -> bool {
    let a2 = dist2(input, i, j);
    let b2 = dist2(input, j, k);
    let c2 = dist2(input, i, k);
    let (s1, s2, s3) = sort_three(a2, b2, c2);

    if realcompare(s3, 4.0 * radius_sq) == "GT" {
        return false;
    }

    if realcompare(s3, s1 + s2) != "LT" {
        return true;
    }

    let cross = triangle_cross(input, i, j, k).abs();
    let lhs = s1 * s2 * s3;
    let rhs = 4.0 * cross * cross * radius_sq;
    realcompare(lhs, rhs) != "GT"
}
